      const userPrompt = `${canonContext ? `CANON CONTEXT:\n${canonContext}\n` : ""}${prevEpisodeText ? `PREVIOUS EPISODE (for escalation check):\n${prevEpisodeText}\n\n` : ""}EPISODE ${episodeNumber} SCRIPT TO VALIDATE:\n${scriptText}`;

